62	def api_chart(ticker, period):
63	    yf_period, interval = PERIOD_MAP.get(period, ("1mo", "1d"))
64	    try:
65	        hist = yf.Ticker(ticker).history(period=yf_period, interval=interval)
66	        if hist.empty:
67	            return jsonify({"error": "No data"}), 404
68	        fmt = "%b %d %H:%M" if interval in ["5m","30m","1h"] else "%b %d"
69	        labels = [idx.strftime(fmt) for idx in hist.index]
70	        prices = [round(p, 2) for p in hist["Close"].tolist()]
71	        first, last = prices[0], prices[-1]
72	        change_pct = round(((last - first) / first) * 100, 2) if first else 0
73	        return jsonify({"labels": labels, "prices": prices, "change_pct": change_pct,
74	                        "positive": change_pct >= 0})
75	    except Exception as e:
76	        return jsonify({"error": str(e)}), 500
