78	def get_image(item):
79	    for ns in ["http://search.yahoo.com/mrss/", "http://www.w3.org/2005/Atom"]:
80	        mc = item.find(f"{{{ns}}}content")
81	        if mc is not None and mc.get("url"):
82	            return mc.get("url")
83	        mc = item.find(f"{{{ns}}}thumbnail")
84	        if mc is not None and mc.get("url"):
85	            return mc.get("url")
86	    enc = item.find("enclosure")
87	    if enc is not None and "image" in enc.get("type",""):
88	        return enc.get("url")
89	    return None
