91	def fetch_news():
92	    articles = []
93	    for url, source in NEWS_FEEDS:
94	        try:
95	            r = requests.get(url, timeout=8, headers={"User-Agent": "Mozilla/5.0"})
96	            root = ET.fromstring(r.content)
97	            for item in root.findall(".//item")[:7]:
98	                title = item.findtext("title","").strip()
99	                link  = item.findtext("link","").strip()
100	                pub   = item.findtext("pubDate","").strip()[:25]
101	                desc  = re.sub("<[^<]+?>","", item.findtext("description",""))[:220].strip()
102	                img   = get_image(item)
103	                if title and link:
104	                    articles.append({"title":title,"link":link,"pub":pub,
105	                                     "source":source,"desc":desc,"img":img})
106	        except:
107	            continue
108	    return articles
